import{e}from"./app.853657db.js";import{_ as i}from"./plugin-vue_export-helper.21dcd24c.js";const t={},a=e('<h2 id="required-reading" tabindex="-1"><a class="header-anchor" href="#required-reading" aria-hidden="true">#</a> Required Reading</h2><p>Unfortunately, there is currently no jailbreak available for firmware version 8.0 to 8.4.1 on 64-bit devices. However, some devices, such as the iPhone 6, can update to 12.5.5 and use the Chimera jailbreak instead.</p><p>This is achieved by simply updating through the Settings application normally. Because the latest available version for these devices is 12.5.5, we can easily update to this firmware version.</p><p>If you have installed update blocking via tvOS Beta profiles, you must first remove that profile before updating. If you don&#39;t know what this means, ignore this.</p><h2 id="removing-profiles" tabindex="-1"><a class="header-anchor" href="#removing-profiles" aria-hidden="true">#</a> Removing Profiles</h2><div class="custom-container tip"><p class="custom-container-title">TIP</p><p>Only follow this if you have installed update blocking in the past.</p></div><ol><li>Open the Settings application</li><li>Tap <code>General</code> -&gt; <code>Profile</code><ul><li>This may also be called <code>Profile and Device Management</code></li></ul></li><li>Tap on the tvOS Beta Software Profile <ul><li>If this is not there, you can skip to the next section of the guide</li></ul></li><li>Tap <code>Remove Downloaded Profile</code></li></ol><h2 id="updating-to-12-5-5" tabindex="-1"><a class="header-anchor" href="#updating-to-12-5-5" aria-hidden="true">#</a> Updating to 12.5.5</h2><ol><li>Plug your device into power and connect to the Internet with Wi-Fi</li><li>Open the Settings application</li><li>Tap <code>General</code> -&gt; <code>Software Update</code><ul><li>Ensure that the version you are updating to is 12.5.5</li></ul></li><li>Download and install the update</li></ol>',9);function o(n,l){return a}var s=i(t,[["render",o]]);export{s as default};
